using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with a default resolver (reflection-based) that knows about common types
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded → {info!.Type.Name}");
}

// Now demonstrate a case where metadata is NOT available.
// Use a resolver that only handles Person, so querying for int[] will fail gracefully.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new LimitedResolver()
};

if (limited.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? arrayInfo))
{
    Console.WriteLine($"TryGetTypeInfo<int[]> succeeded → {arrayInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int[]> returned false — metadata not available");
}

public record Person(string Name, int Age);

// A minimal resolver that only resolves Person
file class LimitedResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(Person))
            return JsonMetadataServices.CreateObjectInfo<Person>(options,
                new JsonObjectInfoValues<Person>());
        return null;
    }
}
